public class Main {

    static long fibonacciIterative(int n) {
        if (n <= 1) return n;

        long a = 0, b = 1;
        for (int i = 2; i <= n; i++) {
            long temp = a + b;
            a = b;
            b = temp;
        }
        return b;
    }

    static long fibonacciRecursive(int n) {
        if (n <= 1) return n;
        return fibonacciRecursive(n - 1) + fibonacciRecursive(n - 2);
    }

    public static void main(String[] args) {
        System.out.println("Iteratif Fibonacci (0-10):");
        for (int i = 0; i <= 10; i++) {
            System.out.print(fibonacciIterative(i) + " ");
        }
        System.out.println();

        System.out.println("\nRecursive Fibonacci (0-10):");
        for (int i = 0; i <= 10; i++) {
            System.out.print(fibonacciRecursive(i) + " ");
        }
        System.out.println();

        System.out.println("\n20. Fibonacci sayisi: " + fibonacciIterative(20));
    }
}
